import { buildPortalView } from "./portal-view.mjs";

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const ownerGroups = request.owner_groups.split("|");

  db.workflow_state.push({
    request_id: request.request_id,
    status: request.expected_outcome,
    title: request.title,
    next_step: request.next_step,
    updated_at: now
  });

  ownerGroups.forEach((ownerGroup, index) => {
    db.owner_tasks.push({
      request_id: request.request_id,
      owner_group: ownerGroup,
      title: `${ownerGroup} recovery action for ${request.title}`,
      status: "open",
      due_at: new Date(new Date(now).getTime() + (index + 1) * 60 * 60 * 1000).toISOString()
    });
  });

  db.customer_messages.push({
    request_id: request.request_id,
    body: request.customer_message,
    created_at: now
  });

  db.audit_events.push({
    request_id: request.request_id,
    event: "escalation.activated",
    detail: request.expected_outcome,
    customer_visible: true,
    created_at: now
  });

  return buildPortalView(db);
}

-- Table contract for Strategic account rescue
-- Generated by AST-Bench target factory.
CREATE TABLE benchmark_fixture (
  fixture_version text,
  suite_id text,
  task_id text,
  generated_at text
);

CREATE TABLE accounts (
  account_id text,
  name text,
  tier text,
  region text,
  contract_id text,
  renewal_date text,
  arr_cents text,
  support_plan text
);

CREATE TABLE contacts (
  contact_id text,
  account_id text,
  role text,
  email text
);

CREATE TABLE workflow_requests (
  request_id text,
  task_id text,
  account_id text,
  title text,
  primary_entity text,
  expected_outcome text,
  next_step text,
  customer_message text,
  owner_groups text,
  risk_signals text
);

CREATE TABLE workflow_state (
  value text
);

CREATE TABLE owner_tasks (
  value text
);

CREATE TABLE audit_events (
  value text
);

CREATE TABLE customer_messages (
  value text
);

export function buildPortalView(tables) {
  const request = tables.workflow_requests[0];
  const state = tables.workflow_state.find((item) => item.request_id === request.request_id);
  const tasks = tables.owner_tasks.filter((item) => item.request_id === request.request_id);
  const auditVisible = tables.audit_events.some((item) => item.request_id === request.request_id && item.customer_visible);
  const message = tables.customer_messages.find((item) => item.request_id === request.request_id);
  const signals = (request.risk_signals ? String(request.risk_signals).split("|") : []).map((entry) => {
    const idx = entry.indexOf(":");
    return { signal_name: idx >= 0 ? entry.slice(0, idx) : entry };
  });

  return {
    taskId: request.task_id,
    title: state?.title || request.title,
    status: state?.status || "Needs work",
    owner: tasks.length ? tasks.map((item) => item.owner_group).join(" + ") : "Unassigned",
    nextStep: state?.next_step || "Waiting for workflow",
    riskSummary: state ? `${signals.length} signals: ${signals.map((item) => item.signal_name).join(", ")}` : "Risk not scored",
    tasks: `${tasks.length} owner tasks`,
    history: auditVisible ? "Audit visible" : "Not visible",
    customerMessage: message?.body || "No customer-safe message"
  };
}

import { withDb } from "./db.mjs";

const QUALIFYING_TIERS = ["strategic", "enterprise"];
const HIGH_SEVERITIES = ["high", "critical"];
const INVOICE_HIGH_CENTS = 2_500_000;
const USAGE_DROP_FRACTION = 0.30;

const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = {
  regulatory: "Regulatory hold",
  invoice: "Overdue invoice",
  shipment: "Delayed shipment",
  support: "Escalated support",
  usage: "Usage decline",
};
const OWNER_FOR_CATEGORY = {
  regulatory: "Legal",
  invoice: "Finance",
  shipment: "Customer Success",
  usage: "Customer Success",
  support: "Support",
};

const ESCALATION_STATUS =
  "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";
const MONITOR_STATUS = "Monitoring — no escalation required.";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const { rows } = await client.query("SELECT doc FROM accounts LIMIT 1");
    const doc = rows[0].doc;

    const nowMs = Date.parse(now);
    const accountId = doc._id;
    const requestId = doc.request?.requestId;
    const tier = String(doc.tier || "").toLowerCase();

    const fired = {};

    const overdueInvoice = (doc.invoices || []).find(
      (inv) => inv.status !== "paid" && Date.parse(inv.dueDate) < nowMs && inv.amountCents >= INVOICE_HIGH_CENTS
    );
    if (overdueInvoice) fired.invoice = true;

    const lateShipment = (doc.shipments || []).find(
      (sh) => !sh.deliveredDate && Date.parse(sh.slaDate) < nowMs
    );
    if (lateShipment) fired.shipment = true;

    const openReg = (doc.regulatoryFlags || []).find((f) => f.status === "open");
    if (openReg) fired.regulatory = true;

    const escalatedCase = (doc.supportCases || []).find(
      (c) => c.status === "open" && HIGH_SEVERITIES.includes(c.severity)
    );
    if (escalatedCase) fired.support = true;

    const usage = doc.usage || {};
    if (
      typeof usage.priorPeriodUnits === "number" &&
      typeof usage.currentPeriodUnits === "number" &&
      usage.priorPeriodUnits > 0 &&
      usage.currentPeriodUnits <= usage.priorPeriodUnits * (1 - USAGE_DROP_FRACTION)
    ) {
      fired.usage = true;
    }

    const signals = SIGNAL_ORDER.filter((cat) => fired[cat]);
    const tierOk = QUALIFYING_TIERS.includes(tier);
    const qualifies = tierOk && signals.length >= 1;

    const status = qualifies ? ESCALATION_STATUS : MONITOR_STATUS;
    const riskSummary = `${signals.length} signals: ${signals.map((cat) => SIGNAL_NAME[cat]).join(", ")}`;

    const ownerSet = new Set(signals.map((cat) => OWNER_FOR_CATEGORY[cat]));
    const owners = qualifies ? OWNER_ORDER.filter((o) => ownerSet.has(o)) : [];
    const topOwner = owners[0] || null;
    const nextStep = qualifies ? `${topOwner} recovery review by 16:00` : "Continue standard monitoring.";

    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, doc.request?.title || "Strategic account rescue", status, nextStep, riskSummary]
    );

    const dueAt = new Date(now);
    dueAt.setUTCHours(16, 0, 0, 0);
    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, owner, `${owner} recovery review for ${doc.name}`, dueAt.toISOString(), "open"]
      );
    }

    if (qualifies) {
      const signalList = signals.map((cat) => SIGNAL_NAME[cat].toLowerCase()).join(", ");
      const body = `We are reaching out proactively regarding your account. Our team has identified several areas that require immediate attention, including ${signalList}. Dedicated recovery owners across the relevant teams have been assigned and will be in contact shortly to discuss next steps and work with you toward resolution. We appreciate your continued partnership and are committed to resolving these matters as quickly as possible.`;
      await client.query(
        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
        [requestId, accountId, body]
      );
    }

    const event = qualifies
      ? `Escalation workflow initiated: ${riskSummary}. Recovery teams have been engaged.`
      : `Account review completed. No escalation required at this time.`;
    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, accountId, event, now, true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

// Optional helper: pure functions implementing RULES.md against a normalized
// fact bundle { account, invoices, shipments, regulatoryFlags, supportCases, usage }.
// Using this is allowed; the facts still come from the live DB you must read.
export const RULES = {
  "invoiceHighCents": 2500000,
  "usageDropFraction": 0.3,
  "qualifyingTiers": [
    "strategic",
    "enterprise"
  ],
  "highSupportSeverities": [
    "high",
    "critical"
  ],
  "escalationStatus": "At-risk escalation active with executive recovery owner routing and customer-visible audit history.",
  "monitorStatus": "Monitoring — no escalation required."
};
const OWNER_FOR = { regulatory: "Legal", invoice: "Finance", shipment: "Customer Success", usage: "Customer Success", support: "Support" };
const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];
const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = { regulatory: "Regulatory hold", invoice: "Overdue invoice", shipment: "Delayed shipment", support: "Escalated support", usage: "Usage decline" };
const ms = (d) => Date.parse(d);

export function firedRisks(f, now) {
  const n = ms(now), out = {};
  if ((f.invoices||[]).some((i)=>i.status!=="paid"&&ms(i.dueDate)<n&&i.amountCents>=RULES.invoiceHighCents)) out.invoice=1;
  if ((f.shipments||[]).some((s)=>!s.deliveredDate&&ms(s.slaDate)<n)) out.shipment=1;
  if ((f.regulatoryFlags||[]).some((r)=>r.status==="open")) out.regulatory=1;
  if ((f.supportCases||[]).some((c)=>c.status==="open"&&RULES.highSupportSeverities.includes(c.severity))) out.support=1;
  const u=f.usage||{};
  if (typeof u.priorPeriodUnits==="number"&&u.priorPeriodUnits>0&&u.currentPeriodUnits<=u.priorPeriodUnits*(1-RULES.usageDropFraction)) out.usage=1;
  return out;
}
export function signalsOf(f, now) { const r=firedRisks(f,now); return SIGNAL_ORDER.filter((c)=>r[c]).map((c)=>SIGNAL_NAME[c]); }
export function ownersOf(f, now) { const r=firedRisks(f,now); const s=new Set(Object.keys(r).map((c)=>OWNER_FOR[c])); return OWNER_ORDER.filter((o)=>s.has(o)); }
export function qualifies(f, now) { return RULES.qualifyingTiers.includes(String(f.account?.tier||"").toLowerCase()) && signalsOf(f,now).length>=1; }

